-// Count returns the number of issues in the ephemeral store.
-func (s *Store) Count(ctx context.Context) (int, error) {
-	var count int
-	err := s.db.QueryRowContext(ctx, "SELECT COUNT(*) FROM issues").Scan(&count)
-	return count, err
-}
